return {
	-- ── Curated keepers (insight-first) ─────────────────────────────
	{ text = "In mathematics you don't understand things — you get used to them.",         author = "John von Neumann" },
	{ text = "The essence of mathematics lies in its freedom.",                            author = "Georg Cantor" },
	{ text = "An equation means nothing unless it expresses a thought of God.",            author = "Srinivasa Ramanujan" },
	{ text = "A mathematician is a device for turning coffee into theorems.",              author = "Paul Erdős" },
	{ text = "A comathematician is a device for turning cotheorems into ffee.",            author = "category theory folklore" },
	{ text = "Mathematics is the art of giving the same name to different things.",        author = "Henri Poincaré" },
	{ text = "To ask the right question is harder than to answer it.",                     author = "Georg Cantor" },
	{ text = "I have had my results — but I do not yet know how to arrive at them.",       author = "Carl Friedrich Gauss" },
	{ text = "Obvious is the most dangerous word in mathematics.",                         author = "E. T. Bell" },
	{ text = "God made the integers; all else is the work of man.",                        author = "Leopold Kronecker" },

	-- ── Additions, same spirit ──────────────────────────────────────
	{ text = "It is by logic that we prove, but by intuition that we discover.",           author = "Henri Poincaré" },
	{ text = "Mathematics is not about numbers or algorithms — it is about understanding.", author = "William Thurston" },
	{ text = "The purpose of computation is insight, not numbers.",                        author = "Richard Hamming" },
	{ text = "It is impossible to be a mathematician without being a poet in soul.",       author = "Sofia Kovalevskaya" },
	{ text = "Mathematics compares the most diverse phenomena and discovers the secret analogies that unite them.", author = "Joseph Fourier" },
	{ text = "If you cannot solve a problem, there is an easier problem you cannot solve: find it.", author = "George Pólya" },
	{ text = "I turn with terror from this lamentable plague of functions which do not have derivatives.", author = "Charles Hermite" },
	{ text = "Topology is the discipline that allows the passage from local to global.",   author = "René Thom" },
	{ text = "If people do not believe mathematics is simple, it's only because they don't realize how complicated life is.", author = "John von Neumann" },
	{ text = "A good mathematical problem is defined by the mathematics it generates.",    author = "Andrew Wiles" },
	{ text = "A proof tells us where to concentrate our doubts.",                          author = "Morris Kline" },
	{ text = "The definition of a category was given in order to define a functor; the definition of a functor, in order to define a natural transformation.", author = "Saunders Mac Lane" },
	{ text = "Young man, you are confusing understanding with familiarity.",               author = "John von Neumann" },
	{ text = "Mathematics is the queen of the sciences, and arithmetic the queen of mathematics — but often she condescends to render service to astronomy and other natural sciences.", author = "Carl Friedrich Gauss" },
	{ text = "Every mathematician worthy of the name has experienced the state of lucid exaltation in which one thought succeeds another as if miraculously.", author = "André Weil" },
	{ text = "Mathematicians are like Frenchmen: whatever you say to them, they translate into their own language — and forthwith it means something entirely different.", author = "Johann Wolfgang von Goethe" },
	{ text = "One geometry cannot be more true than another; it can only be more convenient.", author = "Henri Poincaré" },
	{ text = "In mathematics the art of proposing a question must be held of higher value than solving it.", author = "Georg Cantor" },
	{ text = "A problem worthy of attack proves its worth by fighting back.",              author = "Paul Erdős" },
